import { apiClient } from '@/api/client';
import { ApiErrorHandler } from '../../utils/responseExtractor';
import { ASSET_API } from '../../constants/api';
import type {
  Asset,
  AssetSearchParams,
  AssetListResponse,
  AssetCreateRequest,
  AssetUpdateRequest,
  AssetSearchFilters,
} from './types';

/**
 * 资产核心服务类
 * 提供资产的基础 CRUD 操作
 */
export class AssetCoreService {
  /**
   * 获取资产列表
   */
  async getAssets(params?: AssetSearchParams): Promise<AssetListResponse> {
    try {
      const result = await apiClient.get<AssetListResponse>(ASSET_API.LIST, {
        params: {
          ...params,
          page: params?.page ?? 1,
          limit: params?.limit ?? 20,
        },
        cache: true,
        retry: { maxAttempts: 3, delay: 1000, backoffMultiplier: 2 },
        smartExtract: true,
      });

      if (!result.success) {
        throw new Error(`获取资产列表失败: ${result.error}`);
      }

      return (
        result.data ?? {
          items: [],
          total: 0,
          page: 1,
          limit: 20,
          pages: 0,
        }
      );
    } catch (error) {
      const enhancedError = ApiErrorHandler.handleError(error);
      throw new Error(enhancedError.message);
    }
  }

  /**
   * 获取所有资产（不分页，用于导出等场景）
   */
  async getAllAssets(params?: Omit<AssetSearchParams, 'page' | 'limit'>): Promise<Asset[]> {
    try {
      const result = await apiClient.get<Asset[]>(`${ASSET_API.LIST}/all`, {
        params: {
          ...params,
          limit: 10000,
        },
        cache: true,
        retry: { maxAttempts: 2, delay: 1000, backoffMultiplier: 2 },
        smartExtract: true,
      });

      if (!result.success) {
        throw new Error(`获取所有资产失败: ${result.error}`);
      }

      return result.data!;
    } catch (error) {
      const enhancedError = ApiErrorHandler.handleError(error);
      throw new Error(enhancedError.message);",
