    try {
      const result = await apiClient.post<Asset>(ASSET_API.CREATE, data, {
        retry: false,
        smartExtract: true,
      });

      if (!result.success) {
        throw new Error(`创建资产失败: ${result.error}`);
      }

      return result.data!;
    } catch (error) {
