        retry: false,
        smartExtract: true,
      });

      if (!result.success) {
        throw new Error(`更新资产失败: ${result.error}`);
      }

      return result.data!;
    } catch (error) {
      const enhancedError = ApiErrorHandler.handleError(error);
      throw new Error(enhancedError.message);
    }
  }

  /**
