const fetchAssets = async (params: {
  page: number;
  pageSize: number;
  search?: string;
  filters?: AssetFilters;
}) => {
  try {
    const requestParams: Record<string, string | number> = {
      page: params.page,
      limit: params.pageSize,
    };

    if (params.search !== undefined && params.search !== '') {
      requestParams.search = params.search;
    }

    if (params.filters) {
      const { propertyNature, usageStatus, ownershipStatus, ownershipEntity } = params.filters;

      if (propertyNature !== undefined && propertyNature !== '') {
        requestParams.property_nature = propertyNature;
      }
      if (usageStatus !== undefined && usageStatus !== '') {
        requestParams.usage_status = usageStatus;
      }
      if (ownershipStatus !== undefined && ownershipStatus !== '') {
        requestParams.ownership_status = ownershipStatus;
      }
      if (ownershipEntity !== undefined && ownershipEntity !== '') {
        requestParams.ownership_entity = ownershipEntity;
      }
