      throw new Error(result.error || 'Invalid API response format');
    }

    const responseData = result.data;

    // 转换数据格式以匹配前端期望的格式
    const transformedData = responseData.items
      .map((item: AssetApiResponse) => {
        // 确保所有必需字段都有有效值
        const transformed = {
          id: item.id ?? '',
          propertyName: item.property_name ?? '',
          address: item.address ?? '',
          ownershipEntity: item.ownership_entity ?? '',
          managementEntity: item.management_entity ?? '',
          propertyNature: item.property_nature ?? '',
          usageStatus: item.usage_status ?? '',
          actualPropertyArea: Number(item.total_area) || 0,
          rentableArea: Number(item.usable_area) || 0,
          rentedArea: Number(item.usable_area) || 0,
          occupancyRate: item.usage_status === '出租' ? '100' : '0', // 移除%符号，只保留数字
          ownershipStatus: item.ownership_status ?? '',
          businessCategory: item.business_category ?? '',
          isLitigated:
            item.is_litigated === true || item.is_litigated === 'true' || item.is_litigated === '是'
              ? '是'
              : '否',
          notes: item.notes ?? '',
          createdAt: item.created_at ?? '',
          updatedAt: item.updated_at ?? '',
        };

        // 验证关键字段
        if (
          transformed.id === undefined ||
          transformed.id === '' ||
          transformed.propertyName === undefined ||
          transformed.propertyName === ''
        ) {
          return null;
        }

        return transformed;
      })
      .filter(Boolean); // 过滤掉无效数据

    return {
      data: transformedData,
      total: responseData.total,
      page: responseData.page,
      pageSize: responseData.limit,
    };
  } catch (error) {
    // 提供更详细的错误信息
    const enhancedError = ApiErrorHandler.handleError(error);
    throw new Error(`获取资产列表失败: ${enhancedError.message}`);
  }
};

