  "originalFile": "/**
 * 租金台账页面
 */

import React, { useState, useEffect, useCallback } from 'react';
import {
  Table,
  Card,
  Button,
  Space,
  Tag,
  Input,
  Select,
  DatePicker,
  Modal,
  Tooltip,
  Row,
  Col,
  Statistic,
  Typography,
  Form,
  Alert,
} from 'antd';
import { MessageManager } from '@/utils/messageManager';
import {
  SearchOutlined,
  EditOutlined,
  CheckOutlined,
  ClockCircleOutlined,
  ExclamationCircleOutlined,
  DollarOutlined,
  FileExcelOutlined,
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import dayjs from 'dayjs';

import {
  RentLedger,
  RentLedgerQueryParams,
  RentLedgerPageState,
  RentLedgerUpdate,
  RentStatisticsOverview,
} from '../../types/rentContract';
import { Asset } from '../../types/asset';
import { Ownership } from '../../types/ownership';
import { rentContractService } from '../../services/rentContractService';
import { assetService } from '../../services/assetService';
import { ownershipService } from '../../services/ownershipService';
import { useFormat } from '../../utils/format';
import { createLogger } from '../../utils/logger';
import { COLORS } from '@/styles/colorMap';

const pageLogger = createLogger('RentLedger');

const { Title, Text } = Typography;
const { Search } = Input;
const { Option } = Select;

interface BatchUpdateValues {
  payment_status: '未支付' | '部分支付' | '已支付' | '逾期';
  payment_date?: dayjs.Dayjs;
  payment_method?: string;
  notes?: string;
}

const RentLedgerPage: React.FC = () => {
  const [form] = Form.useForm();

  const [state, setState] = useState<RentLedgerPageState>({
    loading: false,
    ledgers: [],
    pagination: {
      current: 1,
      pageSize: 10,
      total: 0,
