    },
    {
      title: '承租方',
      dataIndex: ['contract', 'tenant_name'],
      key: 'tenant_name',
      render: (text: string) => text || '未知',
    },
    {
      title: '物业名称',
      dataIndex: ['asset', 'property_name'],
      key: 'property_name',
      render: (text: string) => text || '未知',
    },
    {
