          <Form.Item>
            <Space style={{ width: '100%', justifyContent: 'flex-end' }}>
              <Button onClick={() => setState(prev => ({ ...prev, showBatchModal: false }))}>
                取消
              </Button>
              <Button type="primary" htmlType="submit">
                确认更新
              </Button>
            </Space>
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default RentLedgerPage;
