/**
 * 资产表格组件
 * 用于展示资产列表数据，支持排序、筛选、分页、虚拟滚动等功能
 */
const AssetTable: React.FC<AssetTableProps> = ({
  data,
  loading = false,
  onEdit,
  onDelete,
  onView,
  onViewHistory,
  onTableChange,
  selectedRowKeys = [],
  onSelectChange,
  summary,
}) => {
  const columns = getColumns(onView, onEdit, onDelete, onViewHistory);

  // 行选择配置
  const rowSelection: TableRowSelection<Asset> | undefined = onSelectChange
    ? {
        selectedRowKeys,
        onChange: onSelectChange,
        getCheckboxProps: (record: Asset) => ({
          name: record.property_name,
        }),
      }
    : undefined;

  // 移除虚拟滚动组件（antd-virtualized-table已移除）
  // 如需要虚拟滚动，可使用Antd内置的scroll属性或考虑其他方案

  // 根据数据量选择是否使用虚拟滚动
  const itemCount = data?.items?.length ?? 0;
  const shouldUseVirtualScroll = itemCount > 100; // 超过100条记录时使用虚拟滚动

  if (shouldUseVirtualScroll !== undefined && shouldUseVirtualScroll !== null) {
    return (
      <VirtualTable
        data={data}
        loading={loading}
        onEdit={onEdit}
        onDelete={onDelete}
        onView={onView}
        onViewHistory={onViewHistory}
        onTableChange={onTableChange}
        selectedRowKeys={selectedRowKeys}
        onSelectChange={onSelectChange}
        summary={summary}
        height={600}
      />
    );
  }

  // 少量数据时使用标准表格
  return (
    <Table
      columns={columns}
      dataSource={data?.items ?? []}
      rowKey="id"
      loading={loading}
      scroll={{ x: 1800, y: 600 }}
      rowSelection={rowSelection}
      pagination={{
        current: data?.page ?? 1,
        pageSize: data?.limit ?? 20,
        total: data?.total ?? 0,
        showSizeChanger: true,
        showQuickJumper: true,
        showTotal: (total, range) => `第 ${range[0]}-${range[1]} 条，共 ${total} 条记录`,
        pageSizeOptions: ['10', '20', '50', '100'],
        size: 'middle',
      }}
      onChange={onTableChange}
      size="middle"
      bordered
      sticky={{ offsetHeader: 64 }}
      summary={summary}
    />
  );
};

export default React.memo(AssetTable);
